// ওয়েবহুক থেকে body থেকে ডাটা নিন
const { date, time } = $('Check Availability Webhook').first().json.body;
const rows = $input.all();

// Slot কলাম দিয়ে খুঁজি
const slot = rows.find(r => r.json.Slot === time);

if (!slot) {
  return [{
    json: {
      booked_count: 0,
      available: true,
      free_count: 6,
      date, time,
      Slot: time,
      Booked: 0,
      Free: 6,
      free_tables: ['T-1','T-2','T-3','T-4','T-5','T-6'],
      booked_tables: []
    }
  }];
}

const data = slot.json;
const ALL_TABLES = ['T-1','T-2','T-3','T-4','T-5','T-6'];
const bookedTables = ALL_TABLES.filter(t => data[t] === 1);
const freeTables = ALL_TABLES.filter(t => data[t] === 0);

return [{
  json: {
    booked_count: data.Booked || bookedTables.length,
    available: (data.Booked || bookedTables.length) < 6,
    free_count: data.Free || freeTables.length,
    booked_tables: bookedTables,
    free_tables: freeTables,
    date, time,
    Slot: data.Slot,
    Booked: data.Booked,
    Free: data.Free,
    row_number: data.row_number
  }
}];

const booking_id = $('Cancel Booking Webhook').first().json.body.booking_id;
const rows = $input.all();

let rowNumber = null;
for (let i = 0; i < rows.length; i++) {
  if (rows[i].json.ID === booking_id) {
    rowNumber = i + 2;
    break;
  }
}

if (!rowNumber) {
  throw new Error('Booking not found: ' + booking_id);
}

return [{ json: { rowNumber, booking_id } }];

