const req = $('List Bookings Webhook').first().json.body || {};
const filterDate   = (req.date   || '').trim();
const filterSearch = (req.search || '').trim().toLowerCase();
const filterStatus = (req.status || 'all').trim();

const rows = $input.all();

let bookings = rows
  .filter(r => r.json && r.json.ID)
  .map(r => ({
    id:         r.json.ID         || '',
    name:       r.json.Name       || '',
    phone:      r.json.Phone      || '',
    email:      r.json.Email      || '',
    date:       r.json.Date       || '',
    time:       r.json.Time       || '',
    guests:     r.json.Guests     || '',
    status:     r.json.Status     || 'confirmed',
    source:     r.json.Source     || 'online',
    notes:      r.json.Notes      || '',
    created_at: r.json.Created_At || '',
  }));

if (filterDate)             bookings = bookings.filter(b => b.date === filterDate);
if (filterStatus !== 'all') bookings = bookings.filter(b => b.status === filterStatus);
if (filterSearch)           bookings = bookings.filter(b =>
  b.name.toLowerCase().includes(filterSearch) ||
  b.phone.includes(filterSearch) ||
  b.id.toLowerCase().includes(filterSearch)
);

bookings.sort((a, b) => b.created_at.localeCompare(a.created_at));

return [{ json: { bookings, total: bookings.length } }];

const req  = $('Update Booking Webhook').first().json.body;
const bid  = req.booking_id || '';
const rows = $input.all();

// booking_id দিয়ে row খুঁজি (1-indexed, row 1 = header)
let rowIndex = -1;
for(let i = 0; i < rows.length; i++){
  if(rows[i].json.ID === bid){
    rowIndex = i + 2; // +2: row 1 header, i 0-indexed
    break;
  }
}

if(rowIndex === -1){
  return [{ json: { success: false, error: `Booking ${bid} not found`, rowIndex: -1 } }];
}

const existing = rows[rowIndex - 2].json;

// Only update provided fields — বাকিগুলো existing value রাখো
const updated = {
  ID:         existing.ID,
  Name:       req.name    !== undefined ? req.name    : existing.Name,
  Phone:      req.phone   !== undefined ? req.phone   : existing.Phone,
  Email:      req.email   !== undefined ? req.email   : existing.Email,
  Date:       req.date    !== undefined ? req.date    : existing.Date,
  Time:       req.time    !== undefined ? req.time    : existing.Time,
  Table:      req.table   !== undefined ? req.table   : existing.Table,
  Guests:     req.guests  !== undefined ? String(req.guests) : existing.Guests,
  Status:     req.status  !== undefined ? req.status  : existing.Status,
  Source:     existing.Source,
  Notes:      req.notes   !== undefined ? req.notes   : existing.Notes,
  Created_At: existing.Created_At,
};

return [{ json: { ...updated, _rowIndex: rowIndex, success: true } }];
